={
  "query": {
    "kind": "HogQLQuery",
    "query": "SELECT coalesce(properties.$utm_source, 'direct') AS source, coalesce(properties.$utm_medium, '') AS medium, coalesce(properties.$utm_campaign, '') AS campaign, count(DISTINCT distinct_id) AS signups FROM events WHERE event = 'signup_completed' AND timestamp >= toStartOfDay(now() - INTERVAL 1 DAY) AND timestamp < toStartOfDay(now()) GROUP BY source, medium, campaign ORDER BY signups DESC LIMIT 50"
  }
}

parameters.jsCode:
// Parse PostHog HogQL response into acquisition rows for /api/internal/growth/acquisition.
// Expected response shape: { results: [[source, medium, campaign, signups], ...], columns: [...] }
// On auth/config errors fall back gracefully so we still get a Telegram alert.
const body = $input.first()?.json ?? {};
let errorMsg = '';
let raw = [];

if (Array.isArray(body?.results)) {
  raw = body.results;
} else if (body?.detail || body?.code || body?.type) {
  errorMsg = `${body.code || body.type || 'error'}: ${body.detail || 'unknown'}`;
}

const fmt = new Intl.DateTimeFormat('en-CA', {
  timeZone: 'Europe/Kyiv',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
});
const yesterday = new Date(Date.now() - 24 * 60 * 60 * 1000);
const snapshotDate = fmt.format(yesterday);

const rows = raw.map((row) => ({
  source: String(row?.[0] ?? 'direct') || 'direct',
  medium: String(row?.[1] ?? ''),
  campaign: String(row?.[2] ?? ''),
  signups: Number(row?.[3]) || 0,
  spendCents: 0,
  cacCents: null,
}));

const total = rows.reduce((acc, r) => acc + r.signups, 0);
const top = rows
  .slice()
  .sort((a, b) => b.signups - a.signups)
  .slice(0, 5)
  .map((r) => `${r.source}/${r.medium || '—'}: ${r.signups}`)
  .join('\n');

return [
  {
    json: {
      snapshotDate,
      rows,
      summary: { total, top, channelCount: rows.length },
      errorMsg,
    },
  },
];

// ADR-0038, Wave 3 §3.2 — pre-Telegram step that builds a stable
// `alertId` so n8n retries no-op via ON CONFLICT DO NOTHING server-side.
const acq = $('Build acquisition rows').first()?.json ?? {};
const alertId = `${$workflow.id || 'wf63'}:${$execution.id || 'unknown'}:growth-acquisition`;
const summary = acq.errorMsg
  ? `Growth acquisition snapshot error — ${acq.errorMsg}`
  : `Growth acquisition ${acq.snapshotDate} — ${acq.summary?.total ?? 0} signups across ${acq.summary?.channelCount ?? 0} channels.`;
return [{
  json: {
    alertId,
    summary,
    metadata: {
      workflowId: $workflow.id || 'unknown',
      executionId: $execution.id || 'unknown',
      snapshotDate: acq.snapshotDate ?? null,
      total: Number(acq.summary?.total) || 0,
      channelCount: Number(acq.summary?.channelCount) || 0,
      posthogFailed: Boolean(acq.errorMsg),
    },
  },
}];
